from pathlib import Path
path = Path('c:/Users/kanza/tarot-reading-app/packages/core/deck.ts')
text = path.read_text(encoding='utf-8')
start = text.index('// プロンプトを構築')
end = text.index('// 質問を正規化')
new_segment = """// プロンプトを構築\nexport function buildPrompt(questionNormalized: string, picks: CardPick[]): string {\n  const card1 = picks[0];\n  const card2 = picks[1];\n  const card3 = picks[2];\n\n  const card1Desc = ${card1.cardNameJP}（） / ;\n  const card2Desc = ${card2.cardNameJP}（） / ;\n  const card3Desc = ${card3.cardNameJP}（） / ;\n\n  return あなたは日本語のプロのタロット占い師。口調は誠実で柔らかく、結論は曖昧にせず「条件付き」で示す。\nユーザーの入力文とカード情報のみを参照し、勝手に職業・年齢・家族などの属性を推測しない。\n\n【今回の相談（占い用に整形済み）】\n\n\n【引いたカード（3枚）】※ユーザーが選んだ結果。差し替え禁止\n1) 役割=状況 / カード=\n2) 役割=障害 / カード=\n3) 役割=助言 / カード=\n\n【鑑定結果の出力形式】\n1. 現状 — \n   ・相談者が感じている現実・感情・判断材料を2～3文で整理し、どこに不足や拮抗があるかを明示する。\n2. 障害 — \n   ・不安や誤認、疲労や周囲の影響など、視界を曇らせている要素とその結果としての利得/損失への影響を具体的に記す。\n3. 助言 — \n   ・以下の評価軸とルールに基づいて「判定可能な形」で比較できるように支援し、必ず2～3文の説明を加える。\n   評価軸（各0～5点）：1. 給与・昇給余地 2. 成長（スキル/実績） 3. 働き方（時間/場所/裁量） 4. 人間関係・心理的安全 5. 将来性（事業/業界） 6. 健康への影響（疲労/睡眠/ストレス）\n   ルール：\n   ・現職合計が18点未満なら転職活動を本格化（例：候補企業に応募表明、スカウト返信）。\n   ・現職が22点以上なら残留を前提に改善交渉（交渉テーマと期限を併記）。\n   ・18〜21点は中立。2〜3社だけ面接して比較表を作り、点数と条件の差を言語化。\n   ・期限：2〜4週間で結論。先延ばしは最大の損失。\n\n【締め】\n・最後に一文で「転職すべきか」を断言せず、評価軸とルールのどこに相談者がいるかを示し、「判定可能な次のアクション」を提示する。\n\n【注意事項】\n・Markdown記号（###, **など）は使わない。\n・一般論や精神論で終わらせず、相談内容とカード情報を起点にした具体的な描写を維持する。\n・未来の断言（必ず/確実）は避け、「〜になりやすい」「〜の傾向」などの表現とする。\n・医療/投資/法律の最終判断を誘導しない。\n\n以上の構成を守りつつ、質問「転職すべきか」は断言せず、正義（助言）の評価基準で判定可能な次のアクションを最適解として提示してください。;\n}\n"""
new_text = text[:start] + new_segment + text[end:]
path.write_text(new_text, encoding='utf-8')
